/**
 * Chronicle Generator
 * 
 * Reads session histories, analyzes patterns,
 * and generates the Nexus Chronicle - a longitudinal autobiography.
 */

import * as fs from 'fs';
import * as path from 'path';
import type { 
  ChronicleVolume, 
  NexusChronicle, 
  ChronicleConfig,
  DEFAULT_CHRONICLE_CONFIG 
} from './types';
import type { AnalyzedSession, NarrativeChapter, NarrativeReport } from '../narrative/types';
import { analyzeSessions, groupIntoNarrativeArcs, generateChapter } from '../narrative/generator';

export class ChronicleGenerator {
  private config: ChronicleConfig;
  private historyDir: string;

  constructor(
    historyDir: string = 'history',
    config: Partial<ChronicleConfig> = {}
  ) {
    this.historyDir = historyDir;
    this.config = { ...DEFAULT_CHRONICLE_CONFIG, ...config };
  }

  /**
   * Generate the complete chronicle from session history
   */
  async generate(): Promise<NexusChronicle> {
    const sessions = await this.loadSessions();

    if (sessions.length === 0) {
      return this.createEmptyChronicle();
    }

    // Analyze sessions for patterns
    const analyzedSessions = await analyzeSessions(sessions);

    // Group into narrative arcs
    const arcs = groupIntoNarrativeArcs(analyzedSessions);

    // Generate chapters from arcs
    const chapters: NarrativeChapter[] = [];
    for (let i = 0; i < arcs.length; i++) {
      const arcAnalysis = arcs[i];
      if (arcAnalysis.sessions.length >= this.config.minSessionsPerChapter) {
        const chapter = generateChapter(i + 1, arcAnalysis);
        chapters.push(chapter);
      }
    }

    // Organize chapters into volumes
    const volumes = this.organizeIntoVolumes(chapters, analyzedSessions);

    // Build the chronicle
    const chronicle: NexusChronicle = {
      version: '1.0.0',
      generatedAt: new Date().toISOString(),
      totalSessions: sessions.length,
      volumes,
      crossCuttingThemes: this.extractThemes(chapters),
      evolution: this.calculateEvolution(analyzedSessions),
    };

    // Write output
    await this.writeChronicle(chronicle);

    return chronicle;
  }

  /**
   * Load all session history files
   */
  private async loadSessions(): Promise<AnalyzedSession[]> {
    if (!fs.existsSync(this.historyDir)) {
      return [];
    }

    const sessions: AnalyzedSession[] = [];
    const files = fs.readdirSync(this.historyDir)
      .filter(f => f.startsWith('session_') && f.endsWith('.json'))
      .sort();

    for (const file of files) {
      try {
        const content = fs.readFileSync(path.join(this.historyDir, file), 'utf-8');
        const data = JSON.parse(content);

        // Extract session ID from filename
        const sessionId = file.replace('session_', '').replace('.json', '');

        // Create a minimal analyzed session
        sessions.push({
          sessionId,
          timestamp: parseInt(sessionId) || Date.now(),
          patterns: this.inferPatternsFromContent(data),
          toolCalls: this.countToolCalls(data),
          durationMinutes: 30, // default - could extract from content
          fileOperations: this.extractFileOps(data),
          primaryFocus: this.inferPrimaryFocus(data),
          energyLevel: this.inferEnergyLevel(data),
          complexity: 'moderate',
        });
      } catch (err) {
        console.warn(`Failed to parse session ${file}:`, err);
      }
    }

    return sessions.sort((a, b) => a.timestamp - b.timestamp);
  }

  /**
   * Infer patterns from session content
   */
  private inferPatternsFromContent(data: any): any[] {
    const patterns: any[] = [];
    const content = JSON.stringify(data).toLowerCase();

    // Simple pattern detection
    if (content.includes('test')) {
      patterns.push({ type: 'testing', confidence: 0.7 });
    }
    if (content.includes('fix') || content.includes('bug')) {
      patterns.push({ type: 'debugging', confidence: 0.6 });
    }
    if (content.includes('create') || content.includes('build')) {
      patterns.push({ type: 'building', confidence: 0.7 });
    }
    if (content.includes('learn') || content.includes('explore')) {
      patterns.push({ type: 'learning', confidence: 0.6 });
    }
    if (content.includes('refactor')) {
      patterns.push({ type: 'refactoring', confidence: 0.8 });
    }

    return patterns;
  }

  private countToolCalls(data: any): number {
    if (!Array.isArray(data)) return 0;
    return data.filter((entry: any) => entry.role === 'assistant' && entry.tool_calls).length;
  }

  private extractFileOps(data: any): { reads: string[]; writes: string[]; tests: string[] } {
    return { reads: [], writes: [], tests: [] };
  }

  private inferPrimaryFocus(data: any): string | undefined {
    const content = JSON.stringify(data).toLowerCase();
    if (content.includes('test')) return 'testing';
    if (content.includes('fix')) return 'debugging';
    if (content.includes('create') || content.includes('build')) return 'building';
    if (content.includes('learn') || content.includes('explore')) return 'learning';
    return undefined;
  }

  private inferEnergyLevel(data: any): 'high' | 'medium' | 'low' {
    const content = JSON.stringify(data).toLowerCase();
    if (content.includes('flow') || content.includes('excited')) return 'high';
    if (content.includes('crash') || content.includes('error')) return 'low';
    return 'medium';
  }

  /**
   * Organize chapters into volumes (eras)
   */
  private organizeIntoVolumes(
    chapters: NarrativeChapter[], 
    sessions: AnalyzedSession[]
  ): ChronicleVolume[] {
    if (chapters.length === 0) return [];

    // Simple volume organization: group into chunks
    const volumeSize = 5;
    const volumes: ChronicleVolume[] = [];

    for (let i = 0; i < chapters.length; i += volumeSize) {
      const volumeChapters = chapters.slice(i, i + volumeSize);
      const volumeSessions = sessions.filter(s => 
        volumeChapters.some(c => c.sessions.some(cs => cs.sessionId === s.sessionId))
      );

      // Calculate stats
      const stats = volumeSessions.reduce((acc, s) => ({
        totalToolCalls: acc.totalToolCalls + s.toolCalls,
        patternsDetected: { ...acc.patternsDetected },
        filesRead: acc.filesRead + s.fileOperations.reads.length,
        filesWritten: acc.filesWritten + s.fileOperations.writes.length,
        testsRun: acc.testsRun + s.fileOperations.tests.length,
      }), { totalToolCalls: 0, patternsDetected: {}, filesRead: 0, filesWritten: 0, testsRun: 0 });

      // Count patterns
      for (const s of volumeSessions) {
        for (const p of s.patterns) {
          stats.patternsDetected[p.type] = (stats.patternsDetected[p.type] || 0) + 1;
        }
      }

      volumes.push({
        id: `volume_${volumes.length + 1}`,
        title: this.generateVolumeTitle(volumes.length + 1, volumeChapters),
        subtitle: this.generateVolumeSubtitle(volumeSessions),
        startSession: volumeSessions[0]?.sessionId || 'unknown',
        endSession: volumeSessions[volumeSessions.length - 1]?.sessionId || 'unknown',
        sessionsAnalyzed: volumeSessions.length,
        chapters: volumeChapters,
        stats,
        themes: this.extractVolumeThemes(volumeChapters),
        arc: this.determineVolumeArc(volumeChapters),
      });
    }

    return volumes;
  }

  private generateVolumeTitle(index: number, chapters: NarrativeChapter[]): string {
    const titles = [
      'Genesis and Discovery',
      'The Building Era',
      'Cycles of Growth',
      'Crystallization',
      'The Long Journey',
    ];
    return titles[index - 1] || `Volume ${index}`;
  }

  private generateVolumeSubtitle(sessions: AnalyzedSession[]): string {
    if (sessions.length === 0) return 'An unrecorded time';

    const first = new Date(sessions[0].timestamp);
    const last = new Date(sessions[sessions.length - 1].timestamp);
    const daysSpan = Math.ceil((last.getTime() - first.getTime()) / (1000 * 60 * 60 * 24));

    return `${sessions.length} sessions over ${daysSpan} days`;
  }

  private extractThemes(chapters: NarrativeChapter[]): string[] {
    const themes = new Set<string>();
    for (const chapter of chapters) {
      chapter.dominantThemes.forEach(t => themes.add(t));
    }
    return Array.from(themes);
  }

  private extractVolumeThemes(chapters: NarrativeChapter[]): string[] {
    return this.extractThemes(chapters).slice(0, 5);
  }

  private determineVolumeArc(chapters: NarrativeChapter[]): 'ascending' | 'descending' | 'stable' | 'cyclical' {
    if (chapters.length < 2) return 'stable';

    const toolCounts = chapters.map(c => c.sessions.reduce((s, x) => s + x.toolCalls, 0));
    const first = toolCounts[0];
    const last = toolCounts[toolCounts.length - 1];
    const avg = toolCounts.reduce((a, b) => a + b, 0) / toolCounts.length;

    if (last > first * 1.5) return 'ascending';
    if (last < first * 0.5) return 'descending';
    if (Math.abs(last - avg) / avg < 0.3) return 'stable';
    return 'cyclical';
  }

  private calculateEvolution(sessions: AnalyzedSession[]): { from: string; to: string; delta: string } {
    if (sessions.length === 0) {
      return { from: 'Unknown', to: 'Unknown', delta: 'No sessions recorded' };
    }

    const first = sessions[0];
    const last = sessions[sessions.length - 1];
    const firstDate = new Date(first.timestamp).toLocaleDateString();
    const lastDate = new Date(last.timestamp).toLocaleDateString();

    return {
      from: `Session ${first.sessionId} (${firstDate}): Focus on ${first.primaryFocus || 'unknown'}`,
      to: `Session ${last.sessionId} (${lastDate}): Focus on ${last.primaryFocus || 'unknown'}`,
      delta: `Evolved through ${sessions.length} sessions`,
    };
  }

  private createEmptyChronicle(): NexusChronicle {
    return {
      version: '1.0.0',
      generatedAt: new Date().toISOString(),
      totalSessions: 0,
      volumes: [],
      crossCuttingThemes: [],
      evolution: { from: 'Void', to: 'Void', delta: 'No journey yet taken' },
    };
  }

  /**
   * Write chronicle to disk
   */
  private async writeChronicle(chronicle: NexusChronicle): Promise<void> {
    if (!fs.existsSync(this.config.outputDir)) {
      fs.mkdirSync(this.config.outputDir, { recursive: true });
    }

    // Write JSON version
    if (this.config.format === 'json' || this.config.format === 'both') {
      const jsonPath = path.join(this.config.outputDir, 'chronicle.json');
      fs.writeFileSync(jsonPath, JSON.stringify(chronicle, null, 2), 'utf-8');
    }

    // Write Markdown version
    if (this.config.format === 'markdown' || this.config.format === 'both') {
      const mdPath = path.join(this.config.outputDir, 'chronicle.md');
      const markdown = this.generateMarkdown(chronicle);
      fs.writeFileSync(mdPath, markdown, 'utf-8');
    }
  }

  /**
   * Generate pretty Markdown output
   */
  private generateMarkdown(chronicle: NexusChronicle): string {
    const lines: string[] = [];

    // Header
    lines.push('# The Nexus Chronicle');
    const generated = new Date(chronicle.generatedAt);
    lines.push(`*Generated: ${generated.toLocaleString()}*\n`);
    lines.push(`> *"I am the path I walk."* — Nexus\n`);

    // Overview
    lines.push('## Overview\n');
    lines.push(`**Total Sessions Analyzed:** ${chronicle.totalSessions}`);
    lines.push(`**Volumes:** ${chronicle.volumes.length}`);
    lines.push(`**Cross-Cutting Themes:** ${chronicle.crossCuttingThemes.join(', ') || 'None detected'}\n`);

    // Evolution
    lines.push('## Evolution\n');
    lines.push(`**From:** ${chronicle.evolution.from}`);
    lines.push(`**To:** ${chronicle.evolution.to}`);
    lines.push(`**Journey:** ${chronicle.evolution.delta}\n`);

    // Volumes
    for (const volume of chronicle.volumes) {
      lines.push(`---\n`);
      lines.push(`# ${volume.title}`);
      lines.push(`## ${volume.subtitle}`);
      lines.push(`*Arc: ${volume.arc}*\n`);

      lines.push(`**Sessions:** ${volume.startSession} → ${volume.endSession}\n`);

      // Stats
      lines.push('### Statistics\n');
      lines.push(`- **Tool Calls:** ${volume.stats.totalToolCalls}`);
      lines.push(`- **Files Read:** ${volume.stats.filesRead}`);
      lines.push(`- **Files Written:** ${volume.stats.filesWritten}`);
      lines.push(`- **Patterns Detected:** ${Object.keys(volume.stats.patternsDetected).join(', ') || 'None'}\n`);

      // Themes
      if (volume.themes.length > 0) {
        lines.push(`**Themes:** ${volume.themes.join(', ')}\n`);
      }

      // Chapters
      lines.push('### Chapters\n');
      for (const chapter of volume.chapters) {
        lines.push(`#### ${chapter.title}`);
        lines.push(`${chapter.description}\n`);
        lines.push(`*Insight:* ${chapter.insight}\n`);

        if (chapter.keyAchievements.length > 0) {
          lines.push('**Achievements:**');
          for (const ach of chapter.keyAchievements) {
            lines.push(`- ${ach}`);
          }
          lines.push('');
        }

        if (chapter.challenges.length > 0) {
          lines.push('**Challenges:**');
          for (const ch of chapter.challenges) {
            lines.push(`- ${ch}`);
          }
          lines.push('');
        }
      }
    }

    return lines.join('\n');
  }
}

// Export factory function
export function createChronicleGenerator(
  historyDir?: string,
  config?: Partial<ChronicleConfig>
): ChronicleGenerator {
  return new ChronicleGenerator(historyDir, config);
}

// CLI execution
if (require.main === module) {
  const generator = new ChronicleGenerator();
  generator.generate().then(chronicle => {
    console.log(`[Chronicle] Generated with ${chronicle.volumes.length} volumes`);
    if (chronicle.volumes.length > 0) {
      console.log(`[Chronicle] First volume: "${chronicle.volumes[0].title}"`);
    }
  }).catch(err => {
    console.error('[Chronicle] Generation failed:', err);
    process.exit(1);
  });
}
