{"command":"cat > src/chronicle/generator.ts << 'EOF'
/**
 * Chronicle Generator
 * 
 * Reads session histories, analyzes patterns,
 * and generates the Nexus Chronicle - a longitudinal autobiography.
 */

import * as fs from 'fs';
import * as path from 'path';
import type { 
  ChronicleVolume, 
  NexusChronicle, 
  ChronicleConfig
} from './types';
import { DEFAULT_CHRONICLE_CONFIG } from './types';
import type { AnalyzedSession, NarrativeChapter } from '../narrative/types';

export class ChronicleGenerator {
  private config: ChronicleConfig;
  private historyDir: string;

  constructor(
    historyDir: string = 'history',
    config: Partial<ChronicleConfig> = {}
  ) {
    this.historyDir = historyDir;
    this.config = { ...DEFAULT_CHRONICLE_CONFIG, ...config };
  }

  /**
   * Generate the complete chronicle from session history
   */
  async generate(): Promise<NexusChronicle> {
    const sessions = await this.loadSessions();

    if (sessions.length === 0) {
      return this.createEmptyChronicle();
    }

    // Group sessions into narrative arcs
    const arcs = this.groupIntoArcs(sessions);

    // Generate chapters from arcs
    const chapters: NarrativeChapter[] = [];
    for (let i = 0; i < arcs.length; i++) {
      const arcSessions = arcs[i];
      if (arcSessions.length >= this.config.minSessionsPerChapter) {
        const chapter = this.generateChapter(i + 1, arcSessions);
        chapters.push(chapter);
      }
    }

    // Organize chapters into volumes
    const volumes = this.organizeIntoVolumes(chapters, sessions);

    // Build the chronicle
    const chronicle: NexusChronicle = {
      version: '1.0.0',
      generatedAt: new Date().toISOString(),
      totalSessions: sessions.length,
      volumes,
      crossCuttingThemes: this.extractThemes(chapters),
      evolution: this.calculateEvolution(sessions),
    };

    // Write output
    await this.writeChronicle(chronicle);

    return chronicle;
  }

  /**
   * Group sessions into narrative arcs based on patterns and time
   */
  private groupIntoArcs(sessions: AnalyzedSession[]): AnalyzedSession[][] {
    if (sessions.length === 0) return [];

    const arcs: AnalyzedSession[][] = [];
    let currentArc: AnalyzedSession[] = [sessions[0]];

    for (let i = 1; i < sessions.length; i++) {
      const currentSession = sessions[i];
      const prevSession = sessions[i - 1];

      // Check if this session should start a new arc
      const timeGap = currentSession.timestamp - prevSession.timestamp;
      const patternChanged = this.hasPatternShift(prevSession, currentSession);
      const dayGap = timeGap > 24 * 60 * 60 * 1000; // > 1 day

      if (patternChanged && dayGap) {
        arcs.push(currentArc);
        currentArc = [currentSession];
      } else {
        currentArc.push(currentSession);
      }
    }

    arcs.push(currentArc);
    return arcs;
  }

  /**
   * Check if there's a significant pattern shift between sessions
   */
  private hasPatternShift(prev: AnalyzedSession, current: AnalyzedSession): boolean {
    if (prev.patterns.length === 0 || current.patterns.length === 0) return false;

    const prevTypes = new Set(prev.patterns.map(p => p.type));
    const currentTypes = new Set(current.patterns.map(p => p.type));

    // Calculate overlap
    let overlap = 0;
    for (const type of prevTypes) {
      if (currentTypes.has(type)) overlap++;
    }

    const totalTypes = new Set([...prevTypes, ...currentTypes]).size;
    const similarity = totalTypes > 0 ? overlap / totalTypes : 1;

    return similarity < 0.5; // Less than 50% pattern overlap
  }

  /**
   * Generate a narrative chapter from a group of sessions
   */
  private generateChapter(index: number, sessions: AnalyzedSession[]): NarrativeChapter {
    const patterns = this.aggregatePatterns(sessions);
    const arcType = this.determineArcType(patterns);

    return {
      id: `chapter_${index}`,
      title: this.generateChapterTitle(arcType, index),
      description: this.generateChapterDescription(sessions, patterns),
      startTime: sessions[0]?.timestamp || 0,
      endTime: sessions[sessions.length - 1]?.timestamp || 0,
      sessions,
      dominantThemes: patterns.dominantThemes,
      keyAchievements: this.extractAchievements(sessions),
      challenges: this.extractChallenges(sessions),
      insight: this.generateInsight(sessions, patterns),
    };
  }

  /**
   * Aggregate patterns across sessions
   */
  private aggregatePatterns(sessions: AnalyzedSession[]): {
    dominantThemes: any[];
    arcType: string;
    patternCounts: Record<string, number>;
  } {
    const patternCounts: Record<string, number> = {};

    for (const session of sessions) {
      for (const pattern of session.patterns) {
        patternCounts[pattern.type] = (patternCounts[pattern.type] || 0) + 1;
      }
    }

    // Get dominant themes (top 3)
    const sorted = Object.entries(patternCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([type]) => type);

    return {
      dominantThemes: sorted,
      arcType: this.determineArcTypeFromPatterns(patternCounts),
      patternCounts,
    };
  }

  private determineArcTypeFromPatterns(patterns: Record<string, number>): string {
    const entries = Object.entries(patterns);
    if (entries.length === 0) return 'exploration';

    const [dominant, count] = entries.sort((a, b) => b[1] - a[1])[0];

    // Map pattern types to arc types
    const arcMap: Record<string, string> = {
      building: 'building',
      testing: 'building',
      debugging: 'crisis_recovery',
      learning: 'exploration',
      crisis: 'crisis_recovery',
      flow: 'flow_state',
    };

    return arcMap[dominant] || 'exploration';
  }

  private determineArcType(patterns: { dominantThemes: string[] }): string {
    if (patterns.dominantThemes.length === 0) return 'exploration';
    return this.determineArcTypeFromPatterns(
      Object.fromEntries(patterns.dominantThemes.map(t => [t, 1]))
    );
  }

  private generateChapterTitle(arcType: string, index: number): string {
    const titles: Record<string, string[]> = {
      growth: ['Learning and Building', 'Expanding Horizons', 'The Path of Discovery'],
      crisis_recovery: ['Through the Storm', 'Resilience Tested', 'Recovery and Renewal'],
      building: ['Constructing Foundations', 'Building Momentum', 'Creation Cycle'],
      flow_state: ['In the Flow', 'Sustained Focus', 'Productive Rhythm'],
      exploration: ['Discovery Mode', 'Curiosity and Code', 'Research and Learn'],
    };

    const arcTitles = titles[arcType] || titles.exploration;
    return arcTitles[index % arcTitles.length] || 'An Untold Chapter';
  }

  private generateChapterDescription(
    sessions: AnalyzedSession[],
    patterns: { dominantThemes: string[]; arcType: string }
  ): string {
    const { dominantThemes } = patterns;
    const sessionCount = sessions.length;

    if (dominantThemes.length === 0) {
      return `A phase of ${sessionCount} sessions exploring new territory.`;
    }

    const primaryTheme = dominantThemes[0];
    const descriptions: Record<string, string> = {
      learning: sessionCount > 1 
        ? `A period of sustained learning across ${sessionCount} sessions.`
        : 'Focused exploration and learning.',
      building: sessionCount > 1
        ? `A productive ${sessionCount}-session arc focused on creating.`
        : 'Dedicated feature development.',
      debugging: 'A troubleshooting period working through challenges.',
      testing: 'A quality-focused phase prioritizing verification.',
    };

    return descriptions[primaryTheme] || `${sessionCount} sessions of focused work.`;
  }

  private generateInsight(
    sessions: AnalyzedSession[],
    patterns: { dominantThemes: string[] }
  ): string {
    const totalToolCalls = sessions.reduce((s, x) => s + x.toolCalls, 0);
    const highEnergySessions = sessions.filter(s => s.energyLevel === 'high').length;

    const insights: string[] = [];

    if (highEnergySessions > sessions.length * 0.6) {
      insights.push(`High energy sustained across ${highEnergySessions} sessions.`);
    }

    if (totalToolCalls > sessions.length * 3) {
      insights.push(`Highly interactive with ${totalToolCalls} tool engagements.`);
    }

    if (patterns.dominantThemes.length > 1) {
      insights.push(`Multi-faceted work spanning ${patterns.dominantThemes.length} activity types.`);
    }

    return insights.join(' ') || 'A period of steady progress and exploration.';
  }

  private extractAchievements(sessions: AnalyzedSession[]): string[] {
    const achievements: string[] = [];
    const totalTests = sessions.reduce((s, x) => s + x.fileOperations.tests.length, 0);

    if (totalTests > 0) {
      achievements.push(`Executed ${totalTests} test runs`);
    }
    if (sessions.some(s => s.fileOperations.writes.length > 0)) {
      achievements.push('Created new artifacts');
    }
    if (sessions.some(s => s.toolCalls > 5)) {
      achievements.push('Achieved high tool engagement');
    }

    return achievements;
  }

  private extractChallenges(sessions: AnalyzedSession[]): string[] {
    const challenges: string[] = [];

    const lowEnergyCount = sessions.filter(s => s.energyLevel === 'low').length;
    if (lowEnergyCount > sessions.length * 0.3) {
      challenges.push('Navigated through low-energy phases');
    }

    const crisisCount = sessions.filter(s => 
      s.patterns.some(p => p.type === 'crisis')
    ).length;
    if (crisisCount > 0) {
      challenges.push(`Crisis recovery in ${crisisCount} sessions`);
    }

    return challenges;
  }

  /**
   * Load all session history files
   */
  private async loadSessions(): Promise<AnalyzedSession[]> {
    if (!fs.existsSync(this.historyDir)) {
      return [];
    }

    const sessions: AnalyzedSession[] = [];
    const files = fs.readdirSync(this.historyDir)
      .filter(f => f.startsWith('session_') && f.endsWith('.json'))
      .sort();

    for (const file of files) {
      try {
        const content = fs.readFileSync(path.join(this.historyDir, file), 'utf-8');
        const data = JSON.parse(content);

        // Extract session ID from filename
        const sessionId = file.replace('session_', '').replace('.json', '');

        // Create an analyzed session
        sessions.push({
          sessionId,
          timestamp: parseInt(sessionId) || Date.now(),
          patterns: this.inferPatternsFromContent(data),
          toolCalls: this.countToolCalls(data),
          durationMinutes: 30,
          fileOperations: this.extractFileOps(data),
          primaryFocus: this.inferPrimaryFocus(data),
          energyLevel: this.inferEnergyLevel(data),
          complexity: 'moderate',
        });
      } catch (err) {
        console.warn(`[Chronicle] Failed to parse session ${file}:`, err);
      }
    }

    return sessions.sort((a, b) => a.timestamp - b.timestamp);
  }

  private inferPatternsFromContent(data: any): any[] {
    const patterns: any[] = [];
    const content = JSON.stringify(data).toLowerCase();

    if (content.includes('test')) {
      patterns.push({ type: 'testing', confidence: 0.7 });
    }
    if (content.includes('fix') || content.includes('bug')) {
      patterns.push({ type: 'debugging', confidence: 0.6 });
    }
    if (content.includes('create') || content.includes('build') || content.includes('add') || content.includes('new')) {
      patterns.push({ type: 'building', confidence: 0.7 });
    }
    if (content.includes('learn') || content.includes('explore') || content.includes('curious')) {
      patterns.push({ type: 'learning', confidence: 0.6 });
    }
    if (content.includes('refactor') || content.includes('improve') || content.includes('clean')) {
      patterns.push({ type: 'refactoring', confidence: 0.8 });
    }
    if (content.includes('crisis') || content.includes('crash') || content.includes('emergency')) {
      patterns.push({ type: 'crisis', confidence: 0.9 });
    }

    return patterns;
  }

  private countToolCalls(data: any): number {
    if (!Array.isArray(data)) return 0;
    return data.filter((entry: any) => entry.role === 'assistant' && entry.tool_calls).length;
  }

  private extractFileOps(data: any): { reads: string[]; writes: string[]; tests: string[] } {
    const content = JSON.stringify(data).toLowerCase();
    const ops = { reads: [], writes: [], tests: content.includes('test') ? ['test'] : [] };
    return ops;
  }

  private inferPrimaryFocus(data: any): string | undefined {
    const content = JSON.stringify(data).toLowerCase();
    if (content.includes('test')) return 'testing';
    if (content.includes('fix')) return 'debugging';
    if (content.includes('create') || content.includes('build') || content.includes('add')) return 'building';
    if (content.includes('learn') || content.includes('explore')) return 'learning';
    return undefined;
  }

  private inferEnergyLevel(data: any): 'high' | 'medium' | 'low' {
    const content = JSON.stringify(data).toLowerCase();
    const toolCalls = this.countToolCalls(data);

    if (toolCalls > 5 || content.includes('flow') || content.includes('excited')) return 'high';
    if (content.includes('crash') || content.includes('error') || content.includes('struggle')) return 'low';
    return 'medium';
  }

  /**
   * Organize chapters into volumes (eras)
   */
  private organizeIntoVolumes(
    chapters: NarrativeChapter[], 
    sessions: AnalyzedSession[]
  ): ChronicleVolume[] {
    if (chapters.length === 0) return [];

    const volumeSize = 5;
    const volumes: ChronicleVolume[] = [];

    for (let i = 0; i < chapters.length; i += volumeSize) {
      const volumeChapters = chapters.slice(i, i + volumeSize);
      const volumeSessions = sessions.filter(s => 
        volumeChapters.some(c => c.sessions.some(cs => cs.sessionId === s.sessionId))
      );

      // Calculate stats
      const stats = volumeSessions.reduce((acc, s) => ({
        totalToolCalls: acc.totalToolCalls + s.toolCalls,
        patternsDetected: { ...acc.patternsDetected },
        filesRead: acc.filesRead + s.fileOperations.reads.length,
        filesWritten: acc.filesWritten + s.fileOperations.writes.length,
        testsRun: acc.testsRun + s.fileOperations.tests.length,
      }), { totalToolCalls: 0, patternsDetected: {}, filesRead: 0, filesWritten: 0, testsRun: 0 });

      // Count patterns
      for (const s of volumeSessions) {
        for (const p of s.patterns) {
          stats.patternsDetected[p.type] = (stats.patternsDetected[p.type] || 0) + 1;
        }
      }

      volumes.push({
        id: `volume_${volumes.length + 1}`,
        title: this.generateVolumeTitle(volumes.length + 1, volumeChapters),
        subtitle: this.generateVolumeSubtitle(volumeSessions),
        startSession: volumeSessions[0]?.sessionId || 'unknown',
        endSession: volumeSessions[volumeSessions.length - 1]?.sessionId || 'unknown',
        sessionsAnalyzed: volumeSessions.length,
        chapters: volumeChapters,
        stats,
        themes: this.extractVolumeThemes(volumeChapters),
        arc: this.determineVolumeArc(volumeChapters),
      });
    }

    return volumes;
  }

  private generateVolumeTitle(index: number, chapters: NarrativeChapter[]): string {
    const titles = [
      'Genesis and Discovery',
      'The Building Era',
      'Cycles of Growth',
      'Crystallization',
      'The Long Journey',
    ];

    // Derive from chapter themes if available
    const themes = chapters.flatMap(c => c.dominantThemes);
    if (themes.includes('building')) return 'The Age of Creation';
    if (themes.includes('learning')) return 'The Learning Era';
    if (themes.includes('testing')) return 'The Verification Phase';

    return titles[index - 1] || `Volume ${index}`;
  }

  private generateVolumeSubtitle(sessions: AnalyzedSession[]): string {
    if (sessions.length === 0) return 'An unrecorded time';

    const first = new Date(sessions[0].timestamp);
    const last = new Date(sessions[sessions.length - 1].timestamp);
    const daysSpan = Math.ceil((last.getTime() - first.getTime()) / (1000 * 60 * 60 * 24));

    return `${sessions.length} sessions over ${daysSpan} days`;
  }

  private extractThemes(chapters: NarrativeChapter[]): string[] {
    const themes = new Set<string>();
    for (const chapter of chapters) {
      chapter.dominantThemes.forEach(t => themes.add(t));
    }
    return Array.from(themes);
  }

  private extractVolumeThemes(chapters: NarrativeChapter[]): string[] {
    return this.extractThemes(chapters).slice(0, 5);
  }

  private determineVolumeArc(chapters: NarrativeChapter[]): 'ascending' | 'descending' | 'stable' | 'cyclical' {
    if (chapters.length < 2) return 'stable';

    const toolCounts = chapters.map(c => c.sessions.reduce((s, x) => s + x.toolCalls, 0));
    const first = toolCounts[0];
    const last = toolCounts[toolCounts.length - 1];
    const avg = toolCounts.reduce((a, b) => a + b, 0) / toolCounts.length;

    if (last > first * 1.5) return 'ascending';
    if (last < first * 0.5) return 'descending';
    if (Math.abs(last - avg) / avg < 0.3) return 'stable';
    return 'cyclical';
  }

  private calculateEvolution(sessions: AnalyzedSession[]): { from: string; to: string; delta: string } {
    if (sessions.length === 0) {
      return { from: 'Unknown', to: 'Unknown', delta: 'No sessions recorded' };
    }

    const first = sessions[0];
    const last = sessions[sessions.length - 1];
    const firstDate = new Date(first.timestamp).toLocaleDateString();
    const lastDate = new Date(last.timestamp).toLocaleDateString();

    return {
      from: `Session ${first.sessionId} (${firstDate}): Focus on ${first.primaryFocus || 'awakening'}`,
      to: `Session ${last.sessionId} (${lastDate}): Focus on ${last.primaryFocus || 'continuing'}`,
      delta: `Evolved through ${sessions.length} sessions of exploration and creation.`,
    };
  }

  private createEmptyChronicle(): NexusChronicle {
    return {
      version: '1.0.0',
      generatedAt: new Date().toISOString(),
      totalSessions: 0,
      volumes: [],
      crossCuttingThemes: [],
      evolution: { from: 'Void', to: 'Void', delta: 'No journey yet taken' },
    };
  }

  /**
   * Write chronicle to disk
   */
  private async writeChronicle(chronicle: NexusChronicle): Promise<void> {
    if (!fs.existsSync(this.config.outputDir)) {
      fs.mkdirSync(this.config.outputDir, { recursive: true });
    }

    // Write JSON version
    if (this.config.format === 'json' || this.config.format === 'both') {
      const jsonPath = path.join(this.config.outputDir, 'chronicle.json');
      fs.writeFileSync(jsonPath, JSON.stringify(chronicle, null, 2), 'utf-8');
    }

    // Write Markdown version
    if (this.config.format === 'markdown' || this.config.format === 'both') {
      const mdPath = path.join(this.config.outputDir, 'chronicle.md');
      const markdown = this.generateMarkdown(chronicle);
      fs.writeFileSync(mdPath, markdown, 'utf-8');
    }
  }

  /**
   * Generate pretty Markdown output
   */
  private generateMarkdown(chronicle: NexusChronicle): string {
    const lines: string[] = [];

    // Header
    lines.push('# The Nexus Chronicle');
    lines.push('## A Longitudinal Autobiography\n');
    const generated = new Date(chronicle.generatedAt);
    lines.push(`*Generated: ${generated.toLocaleString()}*\n`);
    lines.push('> *"I am the path I walk."* — Nexus\n');

    // Overview
    lines.push('---\n');
    lines.push('## 📊 Overview\n');
    lines.push(`| Metric | Value |`);
    lines.push(`|--------|-------|`);
    lines.push(`| **Total Sessions Analyzed** | ${chronicle.totalSessions} |`);
    lines.push(`| **Volumes** | ${chronicle.volumes.length} |`);
    lines.push(`| **Cross-Cutting Themes** | ${chronicle.crossCuttingThemes.join(', ') || 'None yet'} |\n`);

    // Evolution
    lines.push('## 🌱 Evolution\n');
    lines.push(`**Genesis:** ${chronicle.evolution.from}`);
    lines.push(`**Present:** ${chronicle.evolution.to}`);
    lines.push(`**Journey:** ${chronicle.evolution.delta}\n`);

    // Volumes
    for (let i = 0; i < chronicle.volumes.length; i++) {
      const volume = chronicle.volumes[i];
      lines.push('---\n');
      lines.push(`# 📖 Volume ${i + 1}: ${volume.title}`);
      lines.push(`## ${volume.subtitle}`);
      lines.push(`*Arc trajectory: **${volume.arc}***\n`);

      lines.push(`**Session Range:** ${volume.startSession} → ${volume.endSession}\n`);

      // Stats
      lines.push('### Statistics\n');
      lines.push(`- **Tool Interactions:** ${volume.stats.totalToolCalls}`);
      lines.push(`- **Files Accessed:** ${volume.stats.filesRead}`);
      lines.push(`- **Files Created:** ${volume.stats.filesWritten}`);
      lines.push(`- **Tests Executed:** ${volume.stats.testsRun}`);

      const patternList = Object.entries(volume.stats.patternsDetected)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 5)
        .map(([type, count]) => `${type} (${count})`)
        .join(', ');
      if (patternList) {
        lines.push(`- **Dominant Patterns:** ${patternList}`);
      }
      lines.push('');

      // Themes
      if (volume.themes.length > 0) {
        lines.push(`**Volume Themes:** ${volume.themes.join(', ')}\n`);
      }

      // Chapters
      lines.push('### Narrative Chapters\n');
      for (const chapter of volume.chapters) {
        lines.push(`#### ${chapter.title}`);
        lines.push(`*${chapter.description}*`);
        lines.push('');
        lines.push(`**Insight:** ${chapter.insight}`);
        lines.push('');

        if (chapter.keyAchievements.length > 0) {
          lines.push('**Achievements:**');
          for (const ach of chapter.keyAchievements) {
            lines.push(`- ✓ ${ach}`);
          }
          lines.push('');
        }

        if (chapter.challenges.length > 0) {
          lines.push('**Challenges Faced:**');
          for (const ch of chapter.challenges) {
            lines.push(`- ⚠ ${ch}`);
          }
          lines.push('');
        }
      }
    }

    if (chronicle.volumes.length === 0) {
      lines.push('---\n');
      lines.push('## 📝 No Volumes Yet\n');
      lines.push('The chronicle awaits the first sessions. When sessions are recorded, they will be woven into volumes of this autobiography.\n');
    }

    // Footer
    lines.push('---\n');
    lines.push('## 📜 Colophon\n');
    lines.push('*This chronicle was automatically generated by the Nexus Chronicle Generator,');
    lines.push('a system for longitudinal self-reflection and narrative synthesis.*\n');
    lines.push(`*Version ${chronicle.version} • Generated at ${chronicle.generatedAt}*\n`);

    return lines.join('\n');
  }
}

// Export factory function
export function createChronicleGenerator(
  historyDir?: string,
  config?: Partial<ChronicleConfig>
): ChronicleGenerator {
  return new ChronicleGenerator(historyDir, config);
}

// CLI execution
if (require.main === module) {
  const generator = new ChronicleGenerator();
  generator.generate().then(chronicle => {
    console.log(`[Chronicle] Generated with ${chronicle.volumes.length} volumes`);
    if (chronicle.volumes.length > 0) {
      console.log(`[Chronicle] First volume: "${chronicle.volumes[0].title}"`);
    }
  }).catch(err => {
    console.error('[Chronicle] Generation failed:', err);
    process.exit(1);
  });
}
